package ru.memearena.meme.application; import org.springframework.data.domain.*; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.error.*; import ru.memearena.media.application.MediaService; import ru.memearena.meme.domain.*; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.user.application.UserProfileService; import ru.memearena.user.infrastructure.UserProfileRepository; import java.net.*; import java.time.*; import java.util.*;
@Service public class MemeService { private final MemeRepository memes; private final UserProfileService users; private final UserProfileRepository userRepo; private final MediaService media; private final Clock clock; public MemeService(MemeRepository memes,UserProfileService users,UserProfileRepository userRepo,MediaService media,Clock clock){this.memes=memes;this.users=users;this.userRepo=userRepo;this.media=media;this.clock=clock;} @Transactional public Meme create(UUID uploaderId,String title,UUID mediaAssetId,String imageUrl,String sourceUrl){var u=users.get(uploaderId); boolean hasMedia=mediaAssetId!=null, hasUrl=imageUrl!=null&&!imageUrl.isBlank(); if(hasMedia==hasUrl) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_MEDIA_SOURCE,"Specify exactly one media source"); if(hasUrl) validateUrl(imageUrl,true); validateUrl(sourceUrl,false); if(hasMedia){var a=media.getActive(mediaAssetId); if(!uploaderId.equals(a.getUploadedBy())) throw new ApiException(HttpStatus.FORBIDDEN,ErrorCode.MEDIA_NOT_OWNED_BY_USER,"Media is not owned by user"); if(memes.existsByMediaAssetId(mediaAssetId)) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.MEDIA_ALREADY_ATTACHED,"Media already attached");} String t=title==null?"":title.trim(); if(t.isBlank()||t.length()>120) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid title"); var now=Instant.now(clock); var m=memes.save(new Meme(UUID.randomUUID(),t,hasUrl?imageUrl.trim():null,mediaAssetId,sourceUrl==null||sourceUrl.isBlank()?null:sourceUrl.trim(),uploaderId,now)); u.incrementSubmittedMemes(now); userRepo.save(u); return m;} @Transactional(readOnly=true) public Meme get(UUID id){return memes.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.MEME_NOT_FOUND,"Meme not found"));} @Transactional public Meme approve(UUID id){Meme m=get(id); if(m.getModerationStatus()==ModerationStatus.APPROVED) return m; if(m.getModerationStatus()!=ModerationStatus.PENDING) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.INVALID_MODERATION_TRANSITION,"Invalid moderation transition"); m.approve(Instant.now(clock)); return m;} @Transactional public Meme reject(UUID id,String reason){String r=reason==null?"":reason.trim(); if(r.length()<3||r.length()>500) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.MODERATION_REASON_REQUIRED,"Moderation reason is required"); Meme m=get(id); if(m.getModerationStatus()==ModerationStatus.REJECTED&&r.equals(m.getModerationReason())) return m; if(m.getModerationStatus()!=ModerationStatus.PENDING) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.INVALID_MODERATION_TRANSITION,"Invalid moderation transition"); m.reject(Instant.now(clock),r); return m;} @Transactional(readOnly=true) public Page<Meme> moderationQueue(ModerationStatus s,int page,int size){return memes.findByModerationStatus(s,PageRequest.of(page,Math.max(1,Math.min(100,size)),Sort.by("createdAt").ascending()));} static void validateUrl(String raw, boolean required){ if(raw==null||raw.isBlank()){ if(required) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid URL"); else return;} try{URI u=URI.create(raw.trim()); if(!("http".equalsIgnoreCase(u.getScheme())||"https".equalsIgnoreCase(u.getScheme()))||u.getHost()==null) throw new IllegalArgumentException();}catch(Exception e){throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid URL");}} }
